from flask import Flask, request

app = Flask(__name__)

users = {
    "user1": {"password": "password1", "mfa_enabled": True, "otp": "123456"},
    "user2": {"password": "password2", "mfa_enabled": False}
}

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    user = users.get(username)
    
    if user and user['password'] == password:
        if user.get('mfa_enabled'):
            otp = data.get('otp')
            if otp == user.get('otp'):
                return "Login successful with MFA"
            else:
                return "Invalid OTP"
        else:
            return "Login successful"
    else:
        return "Invalid username or password"

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    user = users.get(username)
    
    if user and user['password'] == password:
        return "Direct login successful"
    else:
        return "Invalid username or password"

